/* eslint-disable no-nested-ternary, no-unused-vars, complexity, no-negated-condition, no-empty-pattern */
import {
  Body,
  Column,
  Head,
  Html,
  Img,
  Preview,
  Row,
  Section,
  Tailwind,
} from "react-email";
import type { TailwindConfig } from "react-email";

import { DefaultFonts } from "@/components/emails/fonts/default";
import { defaultTheme } from "@/components/emails/themes/theme-default";

export type ThreeColumnsImageGridVariant =
  | "default"
  | "slanted-left"
  | "slanted-right";

export interface ThreeColumnsImageGridProps {
  theme?: TailwindConfig;
  imageSrc1?: string;
  imageAlt1?: string;
  imageSrc2?: string;
  imageAlt2?: string;
  imageSrc3?: string;
  imageAlt3?: string;
  variant?: ThreeColumnsImageGridVariant;
}

export const ThreeColumnsImageGridSection = ({
  imageSrc1 = "https://static.photos/nature/200x300/2",
  imageAlt1 = "",
  imageSrc2 = "https://static.photos/nature/200x300/3",
  imageAlt2 = "",
  imageSrc3 = "https://static.photos/nature/200x300/4",
  imageAlt3 = "",
  variant = "default",
}: Omit<ThreeColumnsImageGridProps, "theme">) => {
  const getVariantClass = () => {
    switch (variant) {
      case "slanted-left": {
        return "skew-x-[-10deg]";
      }
      case "slanted-right": {
        return "skew-x-[10deg]";
      }
      default: {
        return "";
      }
    }
  };

  const getUnskewClass = () => {
    switch (variant) {
      case "slanted-left": {
        return "skew-x-[10deg]";
      }
      case "slanted-right": {
        return "skew-x-[-10deg]";
      }
      default: {
        return "";
      }
    }
  };

  return (
    <Section className={`bg-background py-8 ${getVariantClass()}`}>
      <Section className={`max-w-container mx-auto ${getUnskewClass()}`}>
        <Row>
          <Column className="w-1/3 pr-3 align-top">
            <Img
              src={imageSrc1}
              alt={imageAlt1}
              width="200"
              height="300"
              className="w-full h-auto rounded-lg object-cover"
            />
          </Column>
          <Column className="w-1/3 px-3 align-top">
            <Img
              src={imageSrc2}
              alt={imageAlt2}
              width="200"
              height="300"
              className="w-full h-auto rounded-lg object-cover"
            />
          </Column>
          <Column className="w-1/3 pl-3 align-top">
            <Img
              src={imageSrc3}
              alt={imageAlt3}
              width="200"
              height="300"
              className="w-full h-auto rounded-lg object-cover"
            />
          </Column>
        </Row>
      </Section>
    </Section>
  );
};

export const ThreeColumnsImageGrid = ({
  theme = defaultTheme,
  imageSrc1 = "https://static.photos/nature/200x300/5",
  imageAlt1 = "",
  imageSrc2 = "https://static.photos/nature/200x300/6",
  imageAlt2 = "",
  imageSrc3 = "https://static.photos/nature/200x300/7",
  imageAlt3 = "",
  variant = "default",
}: ThreeColumnsImageGridProps) => (
  <Html>
    <Head>
      <DefaultFonts />
    </Head>
    <Preview>Image Grid</Preview>
    <Tailwind config={theme}>
      <Body className="m-0 bg-background font-sans">
        <ThreeColumnsImageGridSection
          imageAlt1={imageAlt1}
          imageAlt2={imageAlt2}
          imageAlt3={imageAlt3}
          imageSrc1={imageSrc1}
          imageSrc2={imageSrc2}
          imageSrc3={imageSrc3}
          variant={variant}
        />
      </Body>
    </Tailwind>
  </Html>
);

ThreeColumnsImageGrid.PreviewProps = {
  imageAlt1: "Image 1",
  imageAlt2: "Image 2",
  imageAlt3: "Image 3",
  imageSrc1: "https://static.photos/nature/200x300/8",
  imageSrc2: "https://static.photos/nature/200x300/9",
  imageSrc3: "https://static.photos/nature/200x300/10",
  theme: defaultTheme,
  variant: "default",
} satisfies ThreeColumnsImageGridProps;
